'use server';

import { redirect } from 'next/navigation';
import { updateTag } from 'next/cache';

type Post = {
  id: number;
  title: string;
};

const posts: Post[] = [];
let nextPostId = 1;

export async function createPost(formData: FormData) {
  const title = formData.get('title');

  if (typeof title !== 'string' || !title.trim()) {
    throw new Error('Title is required.');
  }

  posts.unshift({
    id: nextPostId++,
    title: title.trim()
  });

  updateTag('posts');
  redirect('/');
}

export async function getPosts(): Promise<Post[]> {
  'use cache';
  cacheTag('posts');

  return posts;
}

import { createPost, getPosts } from './actions';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ fontFamily: 'Arial, sans-serif', margin: '40px auto', maxWidth: 640 }}>
      <h1>Posts</h1>

      <form action={createPost} style={{ display: 'grid', gap: 12, marginBottom: 32 }}>
        <label htmlFor="title" style={{ fontWeight: 600 }}>
          New post title
        </label>
        <input
          id="title"
          name="title"
          type="text"
          required
          placeholder="Write a title"
          style={{ padding: 10, fontSize: 16 }}
        />
        <button type="submit" style={{ padding: '10px 16px', width: 'fit-content' }}>
          Create post
        </button>
      </form>

      <section>
        <h2>All posts</h2>
        {posts.length === 0 ? (
          <p>No posts yet.</p>
        ) : (
          <ul style={{ paddingLeft: 20 }}>
            {posts.map((post) => (
              <li key={post.id}>{post.title}</li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}
